from __future__ import annotations

import json
import os
import shlex
import shutil
import subprocess
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = [
    "apps/admin-dashboard",
    "apps/patient-portal",
    "apps/provider-portal",
    "apps/integration-console",
    "apps/public-website",
]
REQUIRED_DIRECTORIES = [
    "apps",
    "services",
    "packages",
    "database",
    "database/migrations",
    "infrastructure/docker",
    "infrastructure/helm/healthbridge",
    "scripts",
]
REQUIRED_FILES = [
    "Makefile",
    "package.json",
    "package-lock.json",
    "docker-compose.yml",
    "database/schema.sql",
    "infrastructure/helm/healthbridge/Chart.yaml",
    "infrastructure/helm/healthbridge/values.yaml",
    "packages/sdk-go/go.mod",
]


def run(command: list[str], cwd: Path = ROOT, input_text: str | None = None) -> None:
    prefix = f"(cd {cwd.relative_to(ROOT)} &&) " if cwd != ROOT else ""
    print("+", prefix + " ".join(command))
    subprocess.run(command, cwd=cwd, check=True, text=True, input=input_text)


def skip(message: str) -> None:
    print(f"skipping {message}")


def require_path(path: Path) -> None:
    if not path.exists():
        raise FileNotFoundError(path.relative_to(ROOT))


def load_json(path: Path) -> object:
    with path.open(encoding="utf-8") as handle:
        return json.load(handle)


def check_required_paths() -> None:
    for directory in REQUIRED_DIRECTORIES:
        path = ROOT / directory
        if not path.is_dir():
            raise FileNotFoundError(directory)

    for filename in REQUIRED_FILES:
        path = ROOT / filename
        if not path.is_file():
            raise FileNotFoundError(filename)

    root_package = load_json(ROOT / "package.json")
    workspaces = root_package.get("workspaces")
    if sorted(workspaces) != sorted(FRONTEND_APPS):
        raise RuntimeError("root package.json workspaces do not match frontend apps")

    for app in FRONTEND_APPS:
        app_dir = ROOT / app
        for filename in ("package.json", "package-lock.json"):
            require_path(app_dir / filename)

        package = load_json(app_dir / "package.json")
        scripts = package.get("scripts", {})
        for script_name in ("test", "build"):
            if script_name not in scripts:
                raise RuntimeError(f"{app}/package.json is missing script {script_name!r}")

    print("verified required repository paths and frontend lockfiles")


def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if "node_modules" in path.parts or "dist" in path.parts:
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files")


def validate_yaml() -> None:
    try:
        import yaml
    except Exception as exc:
        skip(f"yaml validation: {exc}")
        return

    count = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if "node_modules" in path.parts or "dist" in path.parts:
                continue
            if path.is_relative_to(ROOT / "infrastructure/helm") and "templates" in path.parts:
                continue
            with path.open(encoding="utf-8") as handle:
                yaml.safe_load(handle)
            count += 1
    print(f"validated {count} non-template yaml files")


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def run_go_checks() -> None:
    go = shutil.which("go")
    if go is None:
        skip("Go checks: go executable not found")
        return

    run([go, "test", "./..."], cwd=ROOT / "packages/sdk-go")


def run_helm_checks() -> None:
    chart_dir = ROOT / "infrastructure/helm/healthbridge"
    try:
        import yaml
    except Exception as exc:
        skip(f"Helm metadata validation: {exc}")
    else:
        chart = yaml.safe_load((chart_dir / "Chart.yaml").read_text(encoding="utf-8"))
        for key in ("apiVersion", "name", "version", "type"):
            if not chart.get(key):
                raise RuntimeError(f"Chart.yaml is missing {key!r}")
        print("validated Helm chart metadata")

    helm = shutil.which("helm")
    if helm is None:
        skip("Helm lint: helm executable not found")
        return

    run([helm, "lint", str(chart_dir)])


def run_database_checks() -> None:
    schema = ROOT / "database/schema.sql"
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    schema_text = schema.read_text(encoding="utf-8")
    if "CREATE TABLE" not in schema_text.upper():
        raise RuntimeError("database/schema.sql does not define any tables")
    if not migrations:
        raise RuntimeError("database/migrations does not contain SQL migrations")
    print(f"verified database schema and {len(migrations)} migration files")

    psql = shutil.which("psql")
    if psql is None:
        skip("database psql validation: psql executable not found")
        return

    database_url = os.environ.get("HEALTHBRIDGE_VERIFY_DATABASE_URL") or os.environ.get("DATABASE_URL")
    if not database_url:
        skip("database psql validation: HEALTHBRIDGE_VERIFY_DATABASE_URL or DATABASE_URL is not set")
        return

    sql = f"BEGIN;\n\\i {schema}\nROLLBACK;\n"
    run([psql, database_url, "--set", "ON_ERROR_STOP=1", "--file", "-"], input_text=sql)


def dockerfile_context(dockerfile: Path) -> Path:
    if dockerfile.parent.parent == ROOT / "services":
        return dockerfile.parent
    if dockerfile.parent == ROOT / "infrastructure/docker":
        return ROOT
    return dockerfile.parent


def parse_docker_sources(line: str) -> list[str]:
    tokens = shlex.split(line, comments=True)
    if len(tokens) < 3:
        return []
    instruction = tokens[0].upper()
    if instruction not in {"COPY", "ADD"}:
        return []

    rest = tokens[1:]
    if any(token.startswith("--from") for token in rest):
        return []

    while rest and rest[0].startswith("--"):
        rest = rest[1:]
    if len(rest) < 2:
        return []
    return rest[:-1]


def source_exists(context: Path, source: str) -> bool:
    if source.startswith(("http://", "https://")):
        return True

    source = source.lstrip("/")
    if source == ".":
        return context.exists()

    if any(char in source for char in "*?["):
        return bool(list(context.glob(source)))

    return (context / source).exists()


def verify_docker_build_inputs() -> None:
    dockerfiles = sorted(ROOT.glob("services/*/Dockerfile")) + sorted((ROOT / "infrastructure/docker").glob("*.Dockerfile"))
    if not dockerfiles:
        raise RuntimeError("no Dockerfiles found")

    checked_sources = 0
    for dockerfile in dockerfiles:
        context = dockerfile_context(dockerfile)
        require_path(context)
        for line in dockerfile.read_text(encoding="utf-8").splitlines():
            for source in parse_docker_sources(line):
                checked_sources += 1
                if not source_exists(context, source):
                    raise FileNotFoundError(f"{dockerfile.relative_to(ROOT)} references missing source {source!r}")

    print(f"verified {len(dockerfiles)} Dockerfiles and {checked_sources} build input references")


def run_docker_checks() -> None:
    verify_docker_build_inputs()

    docker = shutil.which("docker")
    if docker is None:
        skip("Docker Compose validation: docker executable not found")
        return

    probe = subprocess.run([docker, "compose", "version"], cwd=ROOT, text=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    if probe.returncode != 0:
        skip("Docker Compose validation: docker compose plugin is not available")
        return

    run([docker, "compose", "config", "-q"])


def main() -> None:
    check_required_paths()
    run([sys.executable, "-m", "compileall", "-q", "services", "packages", "scripts"])
    run([sys.executable, "-m", "pytest", "-q"])
    validate_json()
    validate_yaml()
    run_services()
    run_frontends()
    run_go_checks()
    run_helm_checks()
    run_database_checks()
    run_docker_checks()


if __name__ == "__main__":
    main()

